import face_recognition
import numpy as np
import os
import pickle
from flask import Flask, request, jsonify
from PIL import Image
from io import BytesIO
from sklearn.neighbors import KNeighborsClassifier
from sklearn.preprocessing import normalize

# --- Training Script Components (simulate training) ---

# This section represents what you would typically run once to train the model
# and save its state. For this API, it will load a pre-trained state.
# You would structure your employee photos like:
# employees/
#   alice/
#     alice_1.jpg
#     alice_2.png
#   bob/
#     bob_photo.jpeg
#
# A separate script would typically generate 'encodings.pkl' and 'classifier.pkl'

ENCODINGS_FILE = 'encodings.pkl'
CLASSIFIER_FILE = 'classifier.pkl'

def train_facial_recognition_model(employee_photos_dir='employees'):
    known_face_encodings = []
    known_face_names = []

    print("Starting model training...")
    for name in os.listdir(employee_photos_dir):
        person_dir = os.path.join(employee_photos_dir, name)
        if not os.path.isdir(person_dir):
            continue

        print(f"Processing employee: {name}")
        for filename in os.listdir(person_dir):
            if filename.lower().endswith(('.png', '.jpg', '.jpeg')):
                image_path = os.path.join(person_dir, filename)
                try:
                    image = face_recognition.load_image_file(image_path)
                    face_locations = face_recognition.face_locations(image)
                    if face_locations:
                        # Assuming one face per training image for simplicity
                        encoding = face_recognition.face_encodings(image, known_face_locations=[face_locations[0]])[0]
                        known_face_encodings.append(encoding)
                        known_face_names.append(name)
                        print(f"  Added encoding for {name} from {filename}")
                    else:
                        print(f"  No face found in {filename} for {name}")
                except Exception as e:
                    print(f"  Error processing {filename} for {name}: {e}")

    if not known_face_encodings:
        print("No faces found for training. Exiting.")
        return

    # Convert to numpy arrays
    known_face_encodings_np = np.array(known_face_encodings)
    known_face_names_np = np.array(known_face_names)

    # Train a K-Nearest Neighbors classifier
    # n_neighbors can be adjusted. Weights 'distance' means closer points have more influence.
    # We use 'uniform' weights for simplicity as distance is handled by face_recognition itself
    # and we want raw probability.
    # We use a distance-based classifier for "confidence/probability distribution"
    knn_classifier = KNeighborsClassifier(n_neighbors=min(3, len(np.unique(known_face_names))), weights='distance', p=2) # p=2 for Euclidean distance
    knn_classifier.fit(known_face_encodings_np, known_face_names_np)

    with open(ENCODINGS_FILE, 'wb') as f:
        pickle.dump({'encodings': known_face_encodings_np, 'names': known_face_names_np}, f)
    with open(CLASSIFIER_FILE, 'wb') as f:
        pickle.dump(knn_classifier, f)

    print(f"Training complete. Model saved to {ENCODINGS_FILE} and {CLASSIFIER_FILE}")

# --- API Server ---

app = Flask(__name__)

# Global variables to store trained data and classifier
KNOWN_FACE_ENCODINGS = None
KNOWN_FACE_NAMES = None
KNN_CLASSIFIER = None
ALL_KNOWN_LABELS = None

def load_model_data():
    global KNOWN_FACE_ENCODINGS, KNOWN_FACE_NAMES, KNN_CLASSIFIER, ALL_KNOWN_LABELS
    try:
        with open(ENCODINGS_FILE, 'rb') as f:
            data = pickle.load(f)
            KNOWN_FACE_ENCODINGS = data['encodings']
            KNOWN_FACE_NAMES = data['names']
        with open(CLASSIFIER_FILE, 'rb') as f:
            KNN_CLASSIFIER = pickle.load(f)
        ALL_KNOWN_LABELS = sorted(list(KNN_CLASSIFIER.classes_))
        print("Model data loaded successfully.")
    except FileNotFoundError:
        print(f"Error: Model files '{ENCODINGS_FILE}' or '{CLASSIFIER_FILE}' not found.")
        print("Please run the training script or ensure the 'employees' directory exists with photos and retrain.")
        print("For initial setup, call 'train_facial_recognition_model()' before running the app.")
        exit(1) # Exit if model data is not found

@app.before_first_request
def initialize():
    # Make sure 'employees' directory exists for initial training or to ensure model exists
    if not os.path.exists('employees'):
        os.makedirs('employees')
        print("Created 'employees' directory. Please add employee photos and run the training script.")
        # Optionally, run training automatically if no model files exist
        if not os.path.exists(ENCODINGS_FILE) or not os.path.exists(CLASSIFIER_FILE):
             print("No existing model found. Attempting to train from 'employees' directory.")
             train_facial_recognition_model()
             if not os.path.exists(ENCODINGS_FILE) or not os.path.exists(CLASSIFIER_FILE):
                print("Training failed or no faces found. Please ensure 'employees' directory contains valid images.")
                exit(1)

    load_model_data()


@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'file' not in request.files:
        return jsonify({"error": "No file part in the request"}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    try:
        # Load the image using Pillow and convert to numpy array for face_recognition
        pil_image = Image.open(BytesIO(file.read()))
        image_np = np.array(pil_image)

        face_locations = face_recognition.face_locations(image_np)
        face_encodings = face_recognition.face_encodings(image_np, face_locations)

        results = []

        if not face_encodings:
            return jsonify({"message": "No faces found in the image", "results": []})

        for i, face_encoding in enumerate(face_encodings):
            top, right, bottom, left = face_locations[i]

            # Use the trained KNN classifier to get probabilities
            # reshape face_encoding for prediction
            probabilities = KNN_CLASSIFIER.predict_proba(face_encoding.reshape(1, -1))[0]

            # Create a dictionary of probabilities for each known label
            probability_distribution = {label: prob for label, prob in zip(KNN_CLASSIFIER.classes_, probabilities)}

            # Sort probabilities for consistent output
            sorted_probabilities = sorted(probability_distribution.items(), key=lambda item: item[1], reverse=True)

            # Get the best match (highest probability)
            best_match_name = sorted_probabilities[0][0]
            best_match_confidence = sorted_probabilities[0][1]

            results.append({
                "face_number": i + 1,
                "location": {"top": top, "right": right, "bottom": bottom, "left": left},
                "best_match": best_match_name,
                "confidence": float(best_match_confidence), # Convert to float for JSON serialization
                "probability_distribution": {name: float(prob) for name, prob in sorted_probabilities} # Convert all to float
            })

        return jsonify({"message": "Recognition complete", "results": results})

    except Exception as e:
        return jsonify({"error": str(e)}), 500

